122	      () => ({
123	        externalId: nanoid(),
124	        startTime: Date.now(),
125	      })
126	    );
127	
128	    // Step 0: Create job record for tracking
129	    const inngestRunId =
130	      event.id ?? `neural-obs-${sourceEvent.sourceId}-${startTime}`;
131	    const jobId = await step.run("create-job", async () => {
132	      return createJob({
133	        clerkOrgId,
134	        inngestRunId,
135	        inngestFunctionId: "platform/event.capture",
136	        name: `Capture ${sourceEvent.provider}/${sourceEvent.eventType}`,
137	        trigger: "webhook",
138	        input: {
139	          inngestFunctionId: "event.capture",
140	          sourceId: sourceEvent.sourceId,
141	          source: sourceEvent.provider,
142	          sourceType: sourceEvent.eventType,
143	          title: sourceEvent.title,
144	        } satisfies EventCaptureInput,
145	      });
146	    });
147	
148	    await step.run("update-job-running", async () => {
149	      await updateJobStatus(jobId, "running");
150	    });
151	
152	    // Step 1: Check for duplicate
153	    const existing = await step.run("check-duplicate", async () => {
154	      const obs = await db.query.orgEvents.findFirst({
155	        where: and(
156	          eq(orgEvents.clerkOrgId, clerkOrgId),
157	          eq(orgEvents.sourceId, sourceEvent.sourceId)
158	        ),
159	      });
160	
161	      if (obs) {
162	        log.info("observation already exists, skipping", {
163	          observationId: obs.id,
164	          sourceId: sourceEvent.sourceId,
165	        });
166	      }
167	
168	      return obs ?? null;
169	    });
170	
171	    if (existing) {
172	      await step.run("complete-job-duplicate", async () => {
173	        await completeJob({
174	          jobId,
175	          status: "completed",
176	          output: {
177	            inngestFunctionId: "event.capture",
178	            status: "filtered",
179	            reason: "duplicate",
180	            sourceId: sourceEvent.sourceId,
181	          } satisfies EventCaptureOutputFiltered,
182	        });
183	      });
184	
185	      return {
186	        status: "duplicate",
187	        observationId: existing.id,
188	        duration: Date.now() - startTime,
189	      };
190	    }
191	
192	    // Step 2: Check if event is allowed by source config
193	    const gateResult = await step.run("check-event-allowed", async () => {
194	      const attributes = sourceEvent.attributes;
195	
196	      let resourceId: string | undefined;
197	      switch (sourceEvent.provider) {
198	        case "github":
199	          resourceId =
200	            attributes.repoId != null ? String(attributes.repoId) : undefined;
201	          break;
202	        case "vercel":
203	          resourceId =
204	            attributes.projectId != null
205	              ? String(attributes.projectId)
206	              : undefined;
207	          break;
208	        case "sentry":
209	          resourceId =
210	            attributes.projectId != null
211	              ? String(attributes.projectId)
212	              : undefined;
213	          break;
214	        case "linear":
215	          resourceId =
216	            attributes.teamId != null ? String(attributes.teamId) : undefined;
217	          break;
218	        default:
219	          resourceId = undefined;
220	      }
221	
222	      if (!resourceId) {
223	        log.info("no resource ID, rejecting event", {
224	          eventType: sourceEvent.eventType,
225	        });
226	        return {
227	          allowed: false as const,
228	          reason: "event_not_allowed" as const,
229	        };
230	      }
231	
232	      const integration = await db.query.orgIntegrations.findFirst({
233	        where: and(
234	          eq(orgIntegrations.clerkOrgId, clerkOrgId),
235	          eq(orgIntegrations.providerResourceId, resourceId)
236	        ),
237	      });
238	
239	      if (!integration) {
240	        log.info("integration not found, rejecting event", {
241	          resourceId,
242	        });
243	        return {
244	          allowed: false as const,
245	          reason: "event_not_allowed" as const,
246	        };
247	      }
248	
249	      // Gate 2: check integration is active
250	      if (integration.status !== "active") {
251	        log.info("integration not active, rejecting (Gate 2)", {
252	          integrationStatus: integration.status,
253	          statusReason: integration.statusReason,
254	        });
255	        return {
256	          allowed: false as const,
257	          reason: "inactive_connection" as const,
258	        };
259	      }
260	
261	      const baseEventType = getBaseEventType(
262	        sourceEvent.provider,
263	        sourceEvent.eventType
264	      );
265	      const allowed = isEventAllowed(integration.providerConfig, baseEventType);
266	
267	      if (!allowed) {
268	        log.info("event filtered by provider config", {
269	          eventType: sourceEvent.eventType,
270	          baseEventType,
271	          configuredEvents: integration.providerConfig?.sync?.events,
272	        });
273	      }
274	
275	      return {
276	        allowed,
277	        reason: allowed ? ("allowed" as const) : ("event_not_allowed" as const),
278	      };
279	    });
280	
281	    if (!gateResult.allowed) {
282	      const filteredReason =
283	        gateResult.reason === "inactive_connection"
284	          ? ("inactive_connection" as const)
285	          : ("event_not_allowed" as const);
286	
287	      await step.run("complete-job-filtered", async () => {
288	        await completeJob({
289	          jobId,
290	          status: "completed",
291	          output: {
292	            inngestFunctionId: "event.capture",
293	            status: "filtered",
294	            reason: filteredReason,
295	            sourceId: sourceEvent.sourceId,
296	          } satisfies EventCaptureOutputFiltered,
297	        });
298	      });
299	
300	      return {
301	        status: "filtered",
302	        reason:
303	          filteredReason === "inactive_connection"
304	            ? "Integration is not active"
305	            : "Event type not enabled in source config",
306	        duration: Date.now() - startTime,
307	      };
308	    }
309	
310	    // Step 3: Evaluate significance (metadata annotation, not a gate)
311	    const significance = await step.run("evaluate-significance", () => {
312	      return scoreSignificance(sourceEvent);
313	    });
314	
315	    // Step 4: Extract entities (structural categories from relations)
316	    const extractedEntities = await step.run("extract-entities", () => {
317	      const textEntities = extractEntities(sourceEvent.title, sourceEvent.body);
318	      const refEntities = extractFromRelations(sourceEvent.relations);
319	
320	      // Primary entity from sourceEvent.entity — always upserted with highest
321	      // confidence so entity-embed can always find it by (clerkOrgId, category, key).
322	      // value is undefined so refLabel on the junction row stays null (it has no
323	      // relationship-type label — it IS the event's primary subject).
324	      const primaryEntityExtracted: ExtractedEntity = {
325	        category: sourceEvent.entity.entityType as EntityCategory,
326	        key: sourceEvent.entity.entityId,
327	        value: undefined,
328	        confidence: 1.0,
329	        evidence: `Primary entity: ${sourceEvent.entity.entityType}`,
330	        state: sourceEvent.entity.state ?? undefined,
331	        url: sourceEvent.entity.url ?? undefined,
332	      };
333	
334	      // Primary entity first — Map insertion order preserved, so it is always
335	      // at index 0 of deduplicated (used to retrieve externalId after upsert).
336	      const allEntities = [
337	        primaryEntityExtracted,
338	        ...textEntities,
339	        ...refEntities,
340	      ];
341	      const entityMap = new Map<string, ExtractedEntity>();
342	
343	      for (const entity of allEntities) {
344	        const key = `${entity.category}:${entity.key.toLowerCase()}`;
345	        const existingEntity = entityMap.get(key);
346	        if (!existingEntity || existingEntity.confidence < entity.confidence) {
347	          entityMap.set(key, entity);
348	        }
349	      }
350	
351	      const deduplicated = Array.from(entityMap.values());
352	      return deduplicated.slice(0, 50); // MAX_ENTITIES_PER_OBSERVATION
353	    });
354	
355	    // Step 5: Store observation row
356	    const observation = await step.run("store-observation", async () => {
357	      const observationType = deriveObservationType(
358	        sourceEvent.provider,
359	        sourceEvent.eventType
360	      );
361	
362	      const [obs] = await db
363	        .insert(orgEvents)
364	        .values({
365	          externalId,
366	          clerkOrgId,
367	          occurredAt: sourceEvent.occurredAt,
368	          observationType,
369	          title: sourceEvent.title,
370	          content: sourceEvent.body,
371	          source: sourceEvent.provider,
372	          sourceType: sourceEvent.eventType,
373	          sourceId: sourceEvent.sourceId,
374	          sourceReferences: sourceEvent.relations,
375	          metadata: sourceEvent.attributes,
376	          ingestionSource: event.data.ingestionSource ?? "webhook",
377	          ingestLogId: ingestLogId ?? null,
378	          significanceScore: significance.score,
379	        })
380	        .returning();
381	
382	      if (!obs) {
383	        throw new NonRetriableError("Failed to insert observation");
384	      }
385	
386	      log.info("observation stored", {
387	        observationId: obs.id,
388	        externalId: obs.externalId,
389	        observationType,
390	        ingestLogId,
391	      });
392	
393	      return obs;
394	    });
395	
396	    // Step 6: Upsert entities and create junction rows
397	    const entityUpsertResult = await step.run(
398	      "upsert-entities-and-junctions",
399	      async () => {
400	        if (extractedEntities.length === 0) {
401	          return { count: 0, primaryEntityExternalId: null as string | null };
402	        }
403	
404	        // Upsert each entity and get back its ID + externalId for junction inserts.
405	        // externalId is needed to emit entity.upserted with the stable Pinecone vector key.
406	        const entityResults = await Promise.all(
407	          extractedEntities.map((entity) =>
408	            db
409	              .insert(orgEntities)
410	              .values({
411	                clerkOrgId,
412	                category: entity.category,
413	                key: entity.key,
414	                value: entity.value,
415	                evidenceSnippet: entity.evidence,
416	                confidence: entity.confidence,
417	                state: entity.state ?? null,
418	                url: entity.url ?? null,
419	              })
420	              .onConflictDoUpdate({
421	                target: [
422	                  orgEntities.clerkOrgId,
423	                  orgEntities.category,
424	                  orgEntities.key,
425	                ],
426	                set: {
427	                  lastSeenAt: sql`GREATEST(${orgEntities.lastSeenAt}, excluded.${sql.identifier(orgEntities.lastSeenAt.name)})`,
428	                  occurrenceCount: sql`${orgEntities.occurrenceCount} + 1`,
429	                  updatedAt: new Date().toISOString(),
430	                  state: sql`CASE WHEN excluded.${sql.identifier(orgEntities.lastSeenAt.name)} > ${orgEntities.lastSeenAt} THEN excluded.${sql.identifier(orgEntities.state.name)} ELSE ${orgEntities.state} END`,
431	                  url: sql`COALESCE(excluded.${sql.identifier(orgEntities.url.name)}, ${orgEntities.url})`,
432	                },
433	              })
434	              .returning({
435	                id: orgEntities.id,
436	                externalId: orgEntities.externalId,
437	              })
438	          )
439	        );
440	
441	        // Primary entity is always at index 0 (inserted first in extractedEntities,
442	        // Map insertion order preserved, and confidence 1.0 ensures it wins dedup).
443	        const primaryEntityExternalId =
444	          entityResults[0]?.[0]?.externalId ?? null;
445	
446	        // Create junction rows mapping entities to this observation
447	        const junctionRows = entityResults
448	          .map((result, i) => {
449	            const entityId = result[0]?.id;
450	            if (entityId === undefined) {
451	              return null;
452	            }
453	            const entity = extractedEntities[i]!;
454	            return {
455	              entityId,
456	              eventId: observation.id,
457	              clerkOrgId,
458	              category: entity.category,
459	              // Only structural ref entities carry a contextual relationship label.
460	              // The primary entity (index 0) has value=undefined -> refLabel=null.
461	              refLabel: STRUCTURAL_TYPES.has(entity.category)
462	                ? (entity.value ?? null)
463	                : null,
464	            };
465	          })
466	          .filter((row): row is NonNullable<typeof row> => row !== null);
467	
468	        if (junctionRows.length > 0) {
469	          await db
470	            .insert(orgEventEntities)
471	            .values(junctionRows)
472	            .onConflictDoNothing();
473	        }
474	
475	        log.info("entities and junctions stored", {
476	          observationId: observation.id,
477	          entitiesStored: junctionRows.length,
478	          ingestLogId,
479	        });
480	
481	        // Publish to Upstash Realtime for live entity list + entity detail pages
482	        if (primaryEntityExternalId) {
483	          const { realtime } = await import("@repo/app-upstash-realtime");
484	          const channel = realtime.channel(`org-${clerkOrgId}`);
485	
486	          // 1. Entity list live prepend
487	          await channel.emit("org.entity", {
488	            entityExternalId: primaryEntityExternalId,
489	            clerkOrgId,
490	            category: sourceEvent.entity.entityType as EntityCategory,
491	            key: sourceEvent.entity.entityId,
492	            value: null,
493	            state: sourceEvent.entity.state ?? null,
494	            url: sourceEvent.entity.url ?? null,
495	            occurrenceCount: 1, // Approximate — real count is in DB
496	            lastSeenAt: sourceEvent.occurredAt,
497	          });
498	
499	          // 2. Entity detail page live prepend
500	          await channel.emit("org.entityEvent", {
501	            entityExternalId: primaryEntityExternalId,
502	            clerkOrgId,
503	            eventId: observation.id,
504	            eventExternalId: observation.externalId,
505	            observationType: observation.observationType,
506	            title: observation.title,
507	            source: observation.source,
508	            sourceType: observation.sourceType,
509	            sourceId: observation.sourceId,
510	            significanceScore: observation.significanceScore,
511	            occurredAt: observation.occurredAt,
512	            refLabel: null,
513	          });
514	
515	          log.info("entity realtime published", {
516	            entityExternalId: primaryEntityExternalId,
517	            observationId: observation.id,
518	          });
519	        }
520	
521	        return { count: junctionRows.length, primaryEntityExternalId };
522	      }
523	    );
524	
525	    // Build entity refs for entity-graph downstream step.
526	    const entityRefs = [
527	      {
528	        type: sourceEvent.entity.entityType,
529	        key: sourceEvent.entity.entityId,
530	        label: null,
531	      },
532	      ...sourceEvent.relations.map((rel) => ({
533	        type: rel.entityType,
534	        key: rel.entityId,
535	        label: rel.relationshipType,
536	      })),
537	    ];
538	
539	    // Step 7: Emit entity.upserted (triggers entity-graph -> entity-embed chain)
540	    if (entityUpsertResult.primaryEntityExternalId) {
541	      await step.sendEvent("emit-downstream-events", {
542	        name: "platform/entity.upserted" as const,
543	        data: {
544	          clerkOrgId,
545	          entityExternalId: entityUpsertResult.primaryEntityExternalId,
546	          entityType: sourceEvent.entity.entityType,
547	          provider: sourceEvent.provider,
548	          internalEventId: observation.id,
549	          entityRefs,
550	          occurredAt: sourceEvent.occurredAt,
551	          correlationId,
552	        },
553	      });
554	    }
555	
556	    // Step 7b: Emit event.stored (triggers notification dispatch)
557	    await step.sendEvent("emit-event-stored", {
558	      name: "platform/event.stored" as const,
559	      data: {
560	        clerkOrgId,
561	        eventExternalId: observation.externalId,
562	        sourceType: sourceEvent.eventType,
563	        significanceScore: significance.score,
564	        correlationId,
565	      },
566	    });
567	
568	    // Step 8: Complete job with success output
569	    const finalDuration = Date.now() - startTime;
570	    await step.run("complete-job-success", async () => {
571	      await completeJob({
572	        jobId,
573	        status: "completed",
574	        output: {
575	          inngestFunctionId: "event.capture",
576	          status: "success",
577	          observationId: observation.externalId,
578	          observationType: observation.observationType,
579	          significanceScore: significance.score,
580	          entitiesExtracted: entityUpsertResult.count,
581	        } satisfies EventCaptureOutputSuccess,
582	      });
583	    });
584	
585	    return {
586	      status: "stored",
587	      observationId: observation.externalId,
588	      observationType: observation.observationType,
589	      duration: finalDuration,
590	    };
591	  }
592	);
