2	 * Server-side platform caller for non-React contexts.
3	 *
4	 * Use this from backend packages (api/app, etc.) that don't have JSX enabled.
5	 * For React Server Components, use `@repo/platform-trpc/server` instead.
6	 */
7	import {
8	  createPlatformTRPCContext,
9	  platformRouter,
