14	/**
15	 * Create a server-side platform caller for service use.
16	 * Authenticated as the specified caller identity.
17	 *
18	 * @param caller - Service identity (e.g., "app", "platform", "inngest")
19	 */
20	export const createPlatformCaller = cache(async (caller = "app") => {
21	  const token = await signServiceJWT(caller);
22	
23	  const heads = new Headers();
24	  heads.set("x-trpc-source", `${caller}-service`);
25	  heads.set("authorization", `Bearer ${token}`);
26	
27	  const ctx = await createPlatformTRPCContext({ headers: heads });
28	  return platformRouter.createCaller(ctx);
29	});
