1	/**
2	 * Platform service tRPC initialization.
3	 *
4	 * Auth model: service-to-service JWT (not Clerk).
5	 * All callers are internal services (app, platform, inngest, cron).
6	 */
7	import { initTRPC, TRPCError } from "@trpc/server";
8	import { parseError } from "@vendor/observability/error/next";
9	import { log } from "@vendor/observability/log/next";
10	import { createObservabilityMiddleware } from "@vendor/observability/trpc";
11	import superjson from "superjson";
12	import { ZodError } from "zod";
13	
14	import { verifyServiceJWT } from "./lib/jwt";
15	
16	// -- Auth Context -------------------------------------------------------------
17	
18	/**
19	 * Discriminated union for platform service authentication.
20	 * Every request resolves to exactly one variant.
21	 */
22	export type PlatformAuthContext =
23	  | { type: "service"; caller: string }
24	  | { type: "webhook"; provider: string }
25	  | { type: "internal"; source: string }
26	  | { type: "inngest" }
27	  | { type: "cron" }
28	  | { type: "unauthenticated" };
29	
30	/** Explicit context type for tRPC initialization.
31	 *
32	 * Must be used instead of `typeof createPlatformTRPCContext` because the
33	 * context factory only returns "service" | "unauthenticated" — but in-process
34	 * callers (createInternalCaller) provide other auth variants directly.
35	 *
36	 * If you add fields to createPlatformTRPCContext's return type, add them here too.
37	 */
38	export interface PlatformContext {
39	  auth: PlatformAuthContext;
40	  headers: Headers;
41	}
42	
43	// -- Context Creation ---------------------------------------------------------
44	
45	/**
46	 * Create tRPC context for platform service requests.
47	 *
48	 * Auth resolution order:
49	 * 1. Bearer JWT in Authorization header -> service auth
50	 * 2. x-trpc-source header for internal identification
51	 * 3. Unauthenticated fallback
52	 */
53	export const createPlatformTRPCContext = async (opts: {
54	  headers: Headers;
55	}): Promise<PlatformContext> => {
56	  const source = opts.headers.get("x-trpc-source") ?? "unknown";
57	
58	  // Check for service JWT in Authorization header
59	  const authHeader = opts.headers.get("authorization");
60	  if (authHeader?.startsWith("Bearer ")) {
61	    const token = authHeader.replace("Bearer ", "");
62	
63	    try {
64	      const verified = await verifyServiceJWT(token);
65	      log.info("[trpc] platform service request", {
66	        source,
67	        auth: "service",
68	        caller: verified.caller,
69	      });
70	      return {
71	        auth: {
72	          type: "service" as const,
73	          caller: verified.caller,
74	        },
75	        headers: opts.headers,
76	      };
77	    } catch (error) {
78	      log.warn("[trpc] JWT verification error", {
79	        source,
80	        error: parseError(error),
81	      });
82	    }
83	  }
84	
85	  // No authentication
86	  log.info("[trpc] platform service request", {
87	    source,
88	    auth: "unauthenticated",
89	  });
90	  return {
91	    auth: { type: "unauthenticated" as const },
92	    headers: opts.headers,
93	  };
94	};
95	
96	// -- tRPC Initialization ------------------------------------------------------
97	
98	const isProduction = process.env.NODE_ENV === "production";
99	
100	const t = initTRPC.context<PlatformContext>().create({
101	  transformer: superjson,
102	  errorFormatter: ({ shape, error }) => {
103	    const shouldSanitize =
104	      isProduction && error.code === "INTERNAL_SERVER_ERROR";
105	
106	    return {
107	      ...shape,
108	      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
109	      data: {
110	        ...shape.data,
111	        zodError:
112	          error.cause instanceof ZodError ? error.cause.flatten() : null,
113	      },
114	    };
115	  },
116	});
117	
118	// -- Middleware ----------------------------------------------------------------
119	
120	const observabilityMiddleware = t.middleware(
