/**
 * Platform service tRPC initialization.
 *
 * Auth model: service-to-service JWT (not Clerk).
 * All callers are internal services (app, platform, inngest, cron).
 */
import { initTRPC, TRPCError } from "@trpc/server";
import { parseError } from "@vendor/observability/error/next";
import { log } from "@vendor/observability/log/next";
import { createObservabilityMiddleware } from "@vendor/observability/trpc";
import superjson from "superjson";
import { ZodError } from "zod";

import { verifyServiceJWT } from "./lib/jwt";

// -- Auth Context -------------------------------------------------------------

/**
 * Discriminated union for platform service authentication.
 * Every request resolves to exactly one variant.
 */
export type PlatformAuthContext =
  | { type: "service"; caller: string }
  | { type: "webhook"; provider: string }
  | { type: "internal"; source: string }
  | { type: "inngest" }
  | { type: "cron" }
  | { type: "unauthenticated" };

/** Explicit context type for tRPC initialization.
 *
 * Must be used instead of `typeof createPlatformTRPCContext` because the
 * context factory only returns "service" | "unauthenticated" — but in-process
 * callers (createInternalCaller) provide other auth variants directly.
 *
 * If you add fields to createPlatformTRPCContext's return type, add them here too.
 */
export interface PlatformContext {
  auth: PlatformAuthContext;
  headers: Headers;
}

// -- Context Creation ---------------------------------------------------------

/**
 * Create tRPC context for platform service requests.
 *
 * Auth resolution order:
 * 1. Bearer JWT in Authorization header -> service auth
 * 2. x-trpc-source header for internal identification
 * 3. Unauthenticated fallback
 */
export const createPlatformTRPCContext = async (opts: {
  headers: Headers;
}): Promise<PlatformContext> => {
  const source = opts.headers.get("x-trpc-source") ?? "unknown";

  // Check for service JWT in Authorization header
  const authHeader = opts.headers.get("authorization");
  if (authHeader?.startsWith("Bearer ")) {
    const token = authHeader.replace("Bearer ", "");

    try {
      const verified = await verifyServiceJWT(token);
      log.info("[trpc] platform service request", {
        source,
        auth: "service",
        caller: verified.caller,
      });
      return {
        auth: {
          type: "service" as const,
          caller: verified.caller,
        },
        headers: opts.headers,
      };
    } catch (error) {
      log.warn("[trpc] JWT verification error", {
        source,
        error: parseError(error),
      });
    }
  }

  // No authentication
  log.info("[trpc] platform service request", {
    source,
    auth: "unauthenticated",
  });
  return {
    auth: { type: "unauthenticated" as const },
    headers: opts.headers,
  };
};

// -- tRPC Initialization ------------------------------------------------------

const isProduction = process.env.NODE_ENV === "production";

const t = initTRPC.context<PlatformContext>().create({
  transformer: superjson,
  errorFormatter: ({ shape, error }) => {
    const shouldSanitize =
      isProduction && error.code === "INTERNAL_SERVER_ERROR";

    return {
      ...shape,
      message: shouldSanitize ? "An unexpected error occurred" : shape.message,
      data: {
        ...shape.data,
        zodError:
          error.cause instanceof ZodError ? error.cause.flatten() : null,
      },
    };
  },
});

// -- Middleware ----------------------------------------------------------------

const observabilityMiddleware = t.middleware(
  createObservabilityMiddleware({
    isDev: t._config.isDev,
    extractAuth: (ctx) => ({
      ...(ctx.auth.type === "service" && { caller: ctx.auth.caller }),
      ...(ctx.auth.type === "internal" && { source: ctx.auth.source }),
    }),
  })
);

// -- Router & Procedure Exports -----------------------------------------------

export const createTRPCRouter = t.router;
export const createCallerFactory = t.createCallerFactory;

/**
 * Public procedure -- no auth required.
 * Use for health checks or publicly accessible endpoints.
 */
export const publicProcedure = t.procedure.use(observabilityMiddleware);

/**
 * Service procedure -- requires valid service JWT.
 * Used by app or other internal services calling platform.
 *
 * Guarantees `ctx.auth.type === "service"` and `ctx.auth.caller` is available.
 */
export const serviceProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message:
          "Service authentication required. Provide a valid service JWT in the Authorization header.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Admin procedure -- requires service JWT from an admin caller.
 * Used for administrative operations (reindex, purge, etc.).
 *
 * Restricts `ctx.auth.caller` to "admin" only.
 */
export const adminProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type !== "service") {
      throw new TRPCError({
        code: "UNAUTHORIZED",
        message: "Service authentication required.",
      });
    }

    if (ctx.auth.caller !== "admin") {
      throw new TRPCError({
        code: "FORBIDDEN",
        message:
          "Admin access required. This endpoint is restricted to admin callers.",
      });
    }

    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<PlatformAuthContext, { type: "service" }>,
      },
    });
  });

/**
 * Internal procedure -- trusted in-process callers only.
 * Used by Inngest functions and platform route handlers via createInternalCaller().
 *
 * NOT exposed over HTTP. Applies observability middleware without auth checks.
 */
export const internalProcedure = t.procedure.use(observabilityMiddleware);

/**
 * LLM rerank provider
 *
 * Uses Claude Haiku 4.5 via Vercel AI Gateway for semantic relevance scoring.
 * Highest quality reranking with customizable score weighting.
 *
 * Refactored from apps/app/src/lib/neural/llm-filter.ts
 */

import { gateway } from "@ai-sdk/gateway";
import { log } from "@vendor/observability/log/next";
import { generateObject } from "ai";
import { z } from "zod";
import type {
  RerankCandidate,
  RerankOptions,
  RerankProvider,
  RerankResponse,
} from "../types";

/**
 * LLM relevance score schema
 */
const relevanceScoreSchema = z.object({
  scores: z.array(
    z.object({
      id: z.string().describe("The candidate ID"),
      relevance: z
        .number()
        .min(0)
        .max(1)
        .describe(
          "Relevance score from 0.0 (irrelevant) to 1.0 (highly relevant)"
        ),
    })
  ),
});

/**
 * LLM rerank configuration
 */
export interface LLMRerankConfig {
  /**
   * Skip LLM if candidate count is <= this value
   * @default 5
   */
  bypassThreshold?: number;

  /**
   * Weight for LLM score in final calculation
   * @default 0.6
   */
  llmWeight?: number;
  /**
   * Model to use via AI Gateway
   * @default "anthropic/claude-haiku-4.5"
   */
  model?: string;

  /**
   * Minimum relevance threshold to include result
   * @default 0.4
   */
  threshold?: number;

  /**
   * Weight for vector score in final calculation
   * @default 0.4
   */
  vectorWeight?: number;
}

/**
 * Default LLM rerank options
 */
const DEFAULT_CONFIG: Required<LLMRerankConfig> = {
  model: "anthropic/claude-haiku-4.5",
  llmWeight: 0.6,
  vectorWeight: 0.4,
  threshold: 0.4,
  bypassThreshold: 5,
};

/**
 * LLM rerank provider
 *
 * Uses structured output from Claude Haiku for semantic relevance scoring.
 * Combines LLM relevance with vector similarity for final ranking.
 *
 * Features:
 * - Semantic understanding of query intent
 * - Configurable score weighting (LLM vs vector)
 * - Automatic bypass for small result sets
 * - Graceful fallback on errors
 */
export class LLMRerankProvider implements RerankProvider {
  readonly name = "llm";
  private readonly config: Required<LLMRerankConfig>;

  constructor(config?: LLMRerankConfig) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  async rerank(
    query: string,
    candidates: RerankCandidate[],
    options?: RerankOptions
  ): Promise<RerankResponse> {
    const threshold = options?.threshold ?? this.config.threshold;
    const topK = options?.topK ?? candidates.length;
    const requestId = options?.requestId ?? "unknown";
    const minResults = options?.minResults ?? 0;

    if (candidates.length === 0) {
      return {
        results: [],
        latency: 0,
        provider: this.name,
        filtered: 0,
        bypassed: true,
      };
    }

    // Bypass LLM for small result sets
    if (candidates.length <= this.config.bypassThreshold) {
      log.info("LLM rerank bypassed - small result set", {
        requestId,
        candidateCount: candidates.length,
        threshold: this.config.bypassThreshold,
      });

      const results = candidates
        .map((c) => ({
          id: c.id,
          score: c.score,
          relevance: c.score,
          originalScore: c.score,
        }))
        .sort((a, b) => b.score - a.score)
        .slice(0, topK);

      return {
        results,
        latency: 0,
        provider: this.name,
        filtered: 0,
        bypassed: true,
      };
    }

    const startTime = Date.now();

    try {
      const { object } = await generateObject({
        model: gateway(this.config.model),
        schema: relevanceScoreSchema,
        prompt: this.buildPrompt(query, candidates),
        temperature: 0.1, // Low temperature for consistent scoring
      });

      const latency = Date.now() - startTime;

      log.info("LLM rerank complete", {
        requestId,
        latency,
        candidateCount: candidates.length,
        scoresReturned: object.scores.length,
      });

      // Build score map from LLM results
      const scoreMap = new Map(object.scores.map((s) => [s.id, s.relevance]));

      // Combine LLM and vector scores with threshold filtering
      let results = candidates
        .map((c) => {
          const llmRelevance = scoreMap.get(c.id) ?? 0.5; // Default if missing
          const finalScore =
            this.config.llmWeight * llmRelevance +
            this.config.vectorWeight * c.score;
          return {
            id: c.id,
            score: finalScore,
            relevance: llmRelevance,
            originalScore: c.score,
          };
        })
        .filter((r) => r.relevance >= threshold)
        .sort((a, b) => b.score - a.score)
        .slice(0, topK);

      let fallback = false;

      // Minimum results guarantee: if filtering returned too few results,
      // return top results by score regardless of threshold
      if (results.length < minResults && candidates.length > 0) {
        log.info("LLM rerank using minimum results fallback", {
          requestId,
          filteredCount: results.length,
          minResults,
          threshold,
        });

        results = candidates
          .map((c) => {
            const llmRelevance = scoreMap.get(c.id) ?? 0.5;
            const finalScore =
              this.config.llmWeight * llmRelevance +
              this.config.vectorWeight * c.score;
            return {
              id: c.id,
              score: finalScore,
              relevance: llmRelevance,
              originalScore: c.score,
            };
          })
          .sort((a, b) => b.score - a.score)
          .slice(0, Math.min(topK, minResults));

        fallback = true;
      }

      return {
        results,
        latency,
        provider: this.name,
        filtered: candidates.length - results.length,
        bypassed: false,
        fallback,
      };
    } catch (error) {
      const latency = Date.now() - startTime;

      log.error("LLM rerank failed, falling back to vector scores", {
        requestId,
        error,
        latency,
      });

      // Fallback: return candidates sorted by original score
      const results = candidates
        .map((c) => ({
          id: c.id,
          score: c.score,
          relevance: c.score,
          originalScore: c.score,
        }))
        .sort((a, b) => b.score - a.score)
        .slice(0, topK);

      return {
        results,
        latency,
        provider: this.name,
        filtered: 0,
        bypassed: true,
      };
    }
  }

  /**
   * Build the relevance scoring prompt for the LLM
   */
  private buildPrompt(query: string, candidates: RerankCandidate[]): string {
    const candidateList = candidates
      .map(
        (c, i) =>
          `${i + 1}. [${c.id}] "${c.title}": ${c.content.slice(0, 200)}...`
      )
      .join("\n");

    return `You are evaluating search results for relevance to a user query.

User Query: "${query}"

Candidates to score:
${candidateList}

For each candidate, rate its relevance to the query on a scale from 0.0 to 1.0:
- 1.0: Directly answers or highly relevant to the query
- 0.7-0.9: Related and useful context
- 0.4-0.6: Tangentially related
- 0.1-0.3: Barely relevant
- 0.0: Completely irrelevant

Return a score for each candidate by its ID.`;
  }
}

/**
 * Create an LLM rerank provider
 */
export function createLLMRerankProvider(
  config?: LLMRerankConfig
): LLMRerankProvider {
  return new LLMRerankProvider(config);
}

import type { EntityRelation } from "@repo/app-providers/contracts";
import { nanoid } from "@repo/lib";
import { sql } from "drizzle-orm";
import {
  bigint,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  varchar,
} from "drizzle-orm/pg-core";
import { orgIngestLogs } from "./org-ingest-logs";

/**
 * Org events - atomic engineering events from GitHub, Vercel, etc.
 */
export const orgEvents = pgTable(
  "lightfast_org_events",
  {
    /**
     * Internal BIGINT primary key - maximum join/query performance
     */
    id: bigint("id", { mode: "number" })
      .primaryKey()
      .generatedAlwaysAsIdentity(),

    /**
     * External identifier for API responses and Pinecone metadata
     */
    externalId: varchar("external_id", { length: 21 })
      .notNull()
      .$defaultFn(() => nanoid()),

    /**
     * Clerk org ID (no FK — Clerk is source of truth).
     */
    clerkOrgId: varchar("clerk_org_id", { length: 191 }).notNull(),

    // ========== TEMPORAL ==========

    /**
     * When the event occurred in the source system
     */
    occurredAt: timestamp("occurred_at", {
      mode: "string",
      withTimezone: true,
    }).notNull(),

    /**
     * When the event was captured
     */
    capturedAt: timestamp("captured_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),

    // ========== CONTENT ==========

    /**
     * Observation type (e.g., "pr_merged", "deployment_succeeded")
     */
    observationType: varchar("observation_type", { length: 100 }).notNull(),

    /**
     * Short title (<=120 chars, embeddable headline)
     */
    title: text("title").notNull(),

    /**
     * Full content for detailed embedding
     */
    content: text("content").notNull(),

    // ========== SOURCE ==========

    /**
     * Source system (github, vercel, linear, sentry)
     */
    source: varchar("source", { length: 50 }).notNull(),

    /**
     * Source-specific event type (e.g., "pull_request_merged")
     */
    sourceType: varchar("source_type", { length: 100 }).notNull(),

    /**
     * Unique source identifier (e.g., "pr:lightfastai/lightfast#123")
     */
    sourceId: varchar("source_id", { length: 255 }).notNull(),

    /**
     * References to related entities
     */
    sourceReferences: jsonb("source_references").$type<EntityRelation[]>(),

    /**
     * Source-specific attributes
     */
    metadata:
      jsonb("metadata").$type<
        Record<string, string | number | boolean | null>
      >(),

    // ========== INGESTION ==========

    /**
     * How this event was ingested: webhook, backfill, manual, or api
     */
    ingestionSource: varchar("ingestion_source", { length: 20 })
      .default("webhook")
      .notNull(),

    /**
     * FK back to the ingest log that produced this event.
     * Null for backfill-ingested events and test-data paths.
     */
    ingestLogId: bigint("ingest_log_id", { mode: "number" }).references(
      () => orgIngestLogs.id,
      { onDelete: "set null" }
    ),

    /**
     * Significance score (0-100) computed at ingestion time.
     * Used for search ranking and notification thresholds.
     * Null for events ingested before this column was added.
     */
    significanceScore: integer("significance_score"),

    // ========== TIMESTAMPS ==========

    createdAt: timestamp("created_at", {
      mode: "string",
      withTimezone: true,
    })
      .default(sql`CURRENT_TIMESTAMP`)
      .notNull(),
  },
  (table) => ({
    // External ID lookup (API requests)
    externalIdIdx: uniqueIndex("org_event_external_id_idx").on(
      table.externalId
    ),

    // Org + time range queries
    orgOccurredIdx: index("org_event_org_occurred_idx").on(
      table.clerkOrgId,
      table.occurredAt
    ),

    // Source filtering
    sourceIdx: index("org_event_source_idx").on(
      table.clerkOrgId,
      table.source,
      table.sourceType
    ),

    // Deduplication by source ID
    sourceIdIdx: index("org_event_source_id_idx").on(
      table.clerkOrgId,
      table.sourceId
    ),

    // Type filtering
    typeIdx: index("org_event_type_idx").on(
      table.clerkOrgId,
      table.observationType
    ),
  })
);

// Type exports
export type OrgEvent = typeof orgEvents.$inferSelect;
export type InsertOrgEvent = typeof orgEvents.$inferInsert;

